from typing import List
from collections import deque

class Solution:
    def minimumSeconds(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 1:
            return 0

        unique_vals = set(nums)
        min_time = float('inf')

        for val in unique_vals:
            dist = [float('inf')] * n
            q = deque()

            for i in range(n):
                if nums[i] == val:
                    dist[i] = 0
                    q.append(i)

            while q:
                i = q.popleft()
                for j in [(i - 1 + n) % n, (i + 1) % n]:
                    if dist[j] > dist[i] + 1:
                        dist[j] = dist[i] + 1
                        q.append(j)

            max_dist = max(dist)
            min_time = min(min_time, max_dist)

        return min_time
